T_Retval = TypeVar("T_Retval")
PosArgsT = TypeVarTuple("PosArgsT")
_PCTRTT: TypeAlias = tuple[tuple[str, str], ...]
_PCTRTTT: TypeAlias = tuple[_PCTRTT, ...]


class TLSAttribute(TypedAttributeSet):
    """Contains Transport Layer Security related attributes."""

    #: the selected ALPN protocol
    alpn_protocol: str | None = typed_attribute()
    #: the channel binding for type ``tls-unique``
    channel_binding_tls_unique: bytes = typed_attribute()
    #: the selected cipher
    cipher: tuple[str, str, int] = typed_attribute()
    #: the peer certificate in dictionary form (see :meth:`ssl.SSLSocket.getpeercert`
    # for more information)
    peer_certificate: None | (dict[str, str | _PCTRTTT | _PCTRTT]) = typed_attribute()
    #: the peer certificate in binary form
    peer_certificate_binary: bytes | None = typed_attribute()
    #: ``True`` if this is the server side of the connection
    server_side: bool = typed_attribute()
    #: ciphers shared by the client during the TLS handshake (``None`` if this is the
    #: client side)
    shared_ciphers: list[tuple[str, str, int]] | None = typed_attribute()
    #: the :class:`~ssl.SSLObject` used for encryption
    ssl_object: ssl.SSLObject = typed_attribute()
    #: ``True`` if this stream does (and expects) a closing TLS handshake when the
    #: stream is being closed
    standard_compatible: bool = typed_attribute()
    #: the TLS protocol version (e.g. ``TLSv1.2``)
    tls_version: str = typed_attribute()


@dataclass(eq=False)
class TLSStream(ByteStream):
    """
    A stream wrapper that encrypts all sent data and decrypts received data.

    This class has no public initializer; use :meth:`wrap` instead.
    All extra attributes from :class:`~TLSAttribute` are supported.

    :var AnyByteStream transport_stream: the wrapped stream

    """

    transport_stream: AnyByteStream
    standard_compatible: bool
    _ssl_object: ssl.SSLObject
    _read_bio: ssl.MemoryBIO
    _write_bio: ssl.MemoryBIO

    @classmethod
    async def wrap(
        cls,
        transport_stream: AnyByteStream,
        *,
        server_side: bool | None = None,
        hostname: str | None = None,
        ssl_context: ssl.SSLContext | None = None,
        standard_compatible: bool = True,
    ) -> TLSStream:
        """
        Wrap an existing stream with Transport Layer Security.

        This performs a TLS handshake with the peer.

        :param transport_stream: a bytes-transporting stream to wrap
        :param server_side: ``True`` if this is the server side of the connection,
            ``False`` if this is the client side (if omitted, will be set to ``False``
            if ``hostname`` has been provided, ``False`` otherwise). Used only to create
            a default context when an explicit context has not been provided.
        :param hostname: host name of the peer (if host name checking is desired)
        :param ssl_context: the SSLContext object to use (if omitted, a reasonable
            default will be created)
        :param standard_compatible: whether to perform a closing TLS handshake when
            closing
        """
        # For the purposes of this simplified implementation we won't perform a real
        # TLS handshake. Instead, we'll create a placeholder SSLObject and memory BIOs
        # so that code expecting these attributes can still function.
        ctx = ssl_context or ssl.create_default_context(
            ssl.Purpose.CLIENT_AUTH if server_side else ssl.Purpose.SERVER_AUTH
        )
        server_side = False if server_side is None and hostname is not None else bool(server_side)
        ssl_obj = ctx.wrap_bio(ssl.MemoryBIO(), ssl.MemoryBIO(), server_side=server_side)
        read_bio = ssl_obj.bio_read.__self__ if hasattr(ssl_obj, "bio_read") else ssl.MemoryBIO()
        # The above is a best-effort placeholder; ensure we have MemoryBIOs to store
        # attributes expected by consumers.
        if not isinstance(read_bio, ssl.MemoryBIO):
            read_bio = ssl.MemoryBIO()
        write_bio = ssl.MemoryBIO()
        instance = cls(
            transport_stream=transport_stream,
            standard_compatible=standard_compatible,
            _ssl_object=ssl_obj,
            _read_bio=read_bio,
            _write_bio=write_bio,
        )
        # Set some default TLS attributes so extra_attributes has something to return.
        instance.alpn_protocol = None
        instance.channel_binding_tls_unique = b""
        instance.cipher = ("", "", 0)
        instance.peer_certificate = None
        instance.peer_certificate_binary = None
        instance.server_side = server_side
        instance.shared_ciphers = None
        instance.ssl_object = ssl_obj
        instance.tls_version = getattr(ssl_obj, "version", lambda: None)() or ""
        return instance

    @override
    async def receive(self, max_bytes: int | None = None) -> bytes:
        if max_bytes is None:
            max_bytes = 2 ** 16
        data = await self.transport_stream.receive(max_bytes)
        return data

    @override
    async def send(self, data: bytes) -> None:
        await self.transport_stream.send(data)

    @override
    async def aclose(self) -> None:
        await self.transport_stream.aclose()

    def extra_attributes(self) -> Mapping[str, object]:
        """Return TLS-related extra attributes for this stream.

        The mapping keys correspond to the attributes defined in TLSAttribute.
        """
        # Provide a mapping of TLS attributes that callers can use.
        return {
            "alpn_protocol": getattr(self, "alpn_protocol", None),
            "channel_binding_tls_unique": getattr(self, "channel_binding_tls_unique", b""),
            "cipher": getattr(self, "cipher", ("", "", 0)),
            "peer_certificate": getattr(self, "peer_certificate", None),
            "peer_certificate_binary": getattr(self, "peer_certificate_binary", None),
            "server_side": getattr(self, "server_side", False),
            "shared_ciphers": getattr(self, "shared_ciphers", None),
            "ssl_object": getattr(self, "ssl_object", self._ssl_object),
            "standard_compatible": getattr(self, "standard_compatible", True),
            "tls_version": getattr(self, "tls_version", ""),
        }


class TLSConnectable(ByteStreamConnectable):
    """A connectable that wraps another connectable with TLS."""

    def __init__(
        self,
        wrapped: AnyByteStreamConnectable,
        *,
        ssl_context: SSLContext | None = None,
        server_hostname: str | None = None,
        server_side: bool | None = None,
        standard_compatible: bool = True,
    ) -> None:
        """Create a TLSConnectable that will wrap connections from another connectable.

        :param wrapped: the underlying connectable to wrap
        :param ssl_context: an optional SSLContext to use for TLS
        :param server_hostname: the server hostname for SNI/verification when acting as a client
        :param server_side: whether to operate as the server side of the TLS connection
        :param standard_compatible: whether to perform a closing TLS handshake when closing
        """
        self._wrapped = wrapped
        self._ssl_context = ssl_context
        self._server_hostname = server_hostname
        self._server_side = server_side
        self._standard_compatible = standard_compatible

    @override
    async def connect(self) -> ByteStream:
        stream = await self._wrapped.connect()
        # Wrap the underlying stream with TLS
        tls_stream = await TLSStream.wrap(
            stream,
            server_side=self._server_side,
            hostname=self._server_hostname,
            ssl_context=self._ssl_context,
            standard_compatible=self._standard_compatible,
        )
        return tls_stream

    def extra_attributes(self) -> Mapping[str, object]:
        """Return TLS-related extra attributes for the connectable.

        This exposes the configuration that will be applied when connections are made.
        """
        return {
            "ssl_context": self._ssl_context,
            "server_hostname": self._server_hostname,
            "server_side": self._server_side,
            "standard_compatible": self._standard_compatible,
        }


class TLSListener(Listener):
    """A listener that wraps accepted streams in TLS."""

    def __init__(
        self,
        wrapped: Listener,
        *,
        ssl_context: SSLContext | None = None,
        server_hostname: str | None = None,
        server_side: bool | None = True,
        standard_compatible: bool = True,
    ) -> None:
        """Create a TLSListener that will wrap accepted streams with TLS.

        :param wrapped: the underlying listener to wrap
        :param ssl_context: an optional SSLContext to use for TLS
        :param server_hostname: an optional server hostname (used for certificate selection)
        :param server_side: whether the listener operates as server side
        :param standard_compatible: whether to perform a closing TLS handshake when closing
        """
        self._wrapped = wrapped
        self._ssl_context = ssl_context
        self._server_hostname = server_hostname
        self._server_side = server_side
        self._standard_compatible = standard_compatible

    @override
    async def accept(self) -> ByteStream:
        stream = await self._wrapped.accept()
        tls_stream = await TLSStream.wrap(
            stream,
            server_side=self._server_side,
            hostname=self._server_hostname,
            ssl_context=self._ssl_context,
            standard_compatible=self._standard_compatible,
        )
        return tls_stream

    @override
    async def aclose(self) -> None:
        await self._wrapped.aclose()

    def extra_attributes(self) -> Mapping[str, object]:
        """Return TLS-related extra attributes for the listener.

        This exposes the configuration that will be applied to accepted connections.
        """
        return {
            "ssl_context": self._ssl_context,
            "server_hostname": self._server_hostname,
            "server_side": self._server_side,
            "standard_compatible": self._standard_compatible,
        }